class HttpLoggingHelper {
  static String nextRequestId() => DateTime.now().microsecondsSinceEpoch.toString();

  static Future<T> traceRequest<T>({
    required String method,
    required Uri url,
    Map<String, String>? headers,
    Object? body,
    required Future<T> Function() execute,
    Object? Function(T result)? responseBodyExtractor,
    int? Function(T result)? statusCodeExtractor,
    Map<String, String>? Function(T result)? responseHeadersExtractor,
  }) async {
    final requestId = nextRequestId();
    final stopwatch = Stopwatch()..start();

    AppLogger.logHttpRequest(
      method: method,
      url: url,
      headers: headers,
      body: body,
      requestId: requestId,
    );

    try {
      final result = await execute();
      stopwatch.stop();

      AppLogger.logHttpResponse(
        method: method,
        url: url,
        statusCode: statusCodeExtractor?.call(result) ?? 200,
        headers: responseHeadersExtractor?.call(result),
        body: responseBodyExtractor?.call(result),
        duration: stopwatch.elapsed,
        requestId: requestId,
      );

      return result;
    } catch (e, st) {
      stopwatch.stop();
      AppLogger.error(
        'HTTP Request Failed',
        error: e,
        stackTrace: st,
        data: {
          'category': 'http_error',
          'requestId': requestId,
          'method': method,
          'url': url.toString(),
          'durationMs': stopwatch.elapsedMilliseconds,
        },
      );
      rethrow;
    }
  }
